diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 0f86c572639c..e3c63181a065 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -24414,6 +24414,17 @@ bool SLPVectorizerPass::vectorizeGEPIndices(BasicBlock *BB, BoUpSLP &R) {
       // If so, they are marked as deleted, so remove them from the set of
       // candidates.
       Candidates.remove_if([&R](Value *I) {
+    // Ensure all instructions dominate their uses before vectorization. 
+    Candidates.remove_if([&R](Value *I) { 
+        auto *Inst = cast<Instruction>(I); 
+        for (auto *U : Inst->users()) { 
+            if (auto *UserInst = dyn_cast<Instruction>(U)) { 
+                if (!R.getDT()->dominates(Inst, UserInst)) 
+                    return true; 
+            } 
+        } 
+        return false; 
+    });
         return R.isDeleted(cast<Instruction>(I)) ||
                isa<Constant>(cast<GetElementPtrInst>(I)->idx_begin()->get());
       });
